/**
 * Transfer Utilities
 * 
 * Helper functions for transfer operations including recipient formatting
 * and phone number parsing.
 */

import logger from '@/shared/utils/logger.js';

const DEFAULT_COUNTRY_CODE = '+233';

/**
 * Format recipient display label
 */
export const formatRecipientLabel = (recipient) => {
  if (!recipient) {return '';}

  logger.debug('formatRecipientLabel called', { recipient });

  // Handle nested user object from API response
  const user = recipient.user || recipient;

  logger.debug('formatRecipientLabel processing', { user, usertype: recipient.usertype });

  // For business users, prioritize trading_name, then business_name
  if (recipient.usertype === 'business' || user.usertype === 'business') {
    const name = user.trading_name ||
      user.tradingName ||
      user.business_name ||
      user.businessName ||
      user.displayName ||
      user.fullName ||
      user.name ||
      '';
    logger.debug('Business name resolved', { name });
    return name;
  }

  // For individual users
  // First check if displayName was already created by the service
  if (recipient.displayName) {
    logger.debug('Individual name resolved from displayName', { displayName: recipient.displayName });
    return recipient.displayName;
  }

  // Otherwise, construct from first_name and last_name
  if (user.first_name || user.last_name) {
    const fullName = [user.first_name, user.last_name].filter(Boolean).join(' ').trim();
    logger.debug('Individual name resolved from first_name + last_name', { fullName });
    return fullName;
  }

  // Fallback to other fields
  const name = user.displayName ||
    user.fullName ||
    user.name ||
    user.email ||
    user.phone ||
    user.walletNumber ||
    '';
  logger.debug('Individual name resolved (fallback)', { name });
  return name;
};

/**
 * Format recipient sub-label (phone, account number, etc.)
 */
export const formatRecipientSubLabel = (recipient) => {
  if (!recipient) {return '';}
  const parts = [
    recipient.phoneNumber || recipient.phone || recipient.accountNumber,
    recipient.usertype && recipient.usertype !== 'individual' ? recipient.usertype : null,
  ].filter(Boolean);
  return parts.join(' · ');
};

/**
 * Extract recipient ID from recipient object
 */
export const extractRecipientId = (recipient) => {
  if (!recipient) {return '';}

  // Handle nested user object from API response
  const user = recipient.user || recipient;

  const id = (
    user.id ||
    user.recipientId ||
    user.userId ||
    user.walletId ||
    user.accountId ||
    user.contactId ||
    recipient.id ||
    recipient.recipientId ||
    recipient.userId ||
    recipient.walletId ||
    recipient.accountId ||
    recipient.contactId ||
    ''
  );

  logger.debug('extractRecipientId result', { 
    recipient, 
    user, 
    extractedId: id,
    availableFields: {
      'user.id': user.id,
      'user.recipientId': user.recipientId,
      'user.userId': user.userId,
      'user.walletId': user.walletId,
      'recipient.id': recipient.id,
      'recipient.recipientId': recipient.recipientId,
      'recipient.userId': recipient.userId
    }
  });

  return id;
};

/**
 * Split phone number into country code and national number
 */
export const splitPhoneNumber = (value, countries = [], defaultCountryCode = DEFAULT_COUNTRY_CODE) => {
  const sanitized = String(value || '').replace(/\s+/g, '');
  if (!sanitized) {
    return { countryCode: defaultCountryCode, nationalNumber: '' };
  }

  const digitsOnly = sanitized.replace(/[^0-9]/g, '');
  if (!digitsOnly) {
    return { countryCode: defaultCountryCode, nationalNumber: '' };
  }

  // Handle case where countries array is not provided or is empty
  if (!Array.isArray(countries) || countries.length === 0) {
    // If phone starts with default country code, extract it
    const defaultCodeDigits = defaultCountryCode.replace(/[^0-9]/g, '');
    if (digitsOnly.startsWith(defaultCodeDigits)) {
      const nationalDigits = digitsOnly.slice(defaultCodeDigits.length);
      return {
        countryCode: defaultCountryCode,
        nationalNumber: nationalDigits || '',
      };
    }
    // Otherwise, return the whole number as national number
    return { countryCode: defaultCountryCode, nationalNumber: digitsOnly };
  }

  const matchingCountry = countries.find((country) => {
    if (!country || !country.dialCode) {return false;}
    const dialDigits = country.dialCode.replace(/[^0-9]/g, '');
    return dialDigits && digitsOnly.startsWith(dialDigits);
  });

  if (matchingCountry) {
    const dialDigits = matchingCountry.dialCode.replace(/[^0-9]/g, '');
    const nationalDigits = digitsOnly.slice(dialDigits.length);
    return {
      countryCode: matchingCountry.dialCode,
      nationalNumber: nationalDigits || '',
    };
  }

  return { countryCode: defaultCountryCode, nationalNumber: digitsOnly };
};

export { DEFAULT_COUNTRY_CODE };

