/**
 * Custom Hook for Transfer Sender ID
 * 
 * Resolves sender ID from user data stored in localStorage.
 */

import { useMemo } from 'react';
import { tokenService } from '@/features/auth/services';
import logger from '@/shared/utils/logger.js';

export const useTransferSender = () => {
  const senderId = useMemo(() => {
    try {
      const user = tokenService.getUserData();
      if (!user) {
        logger.warn('No user data found in localStorage');
        return null;
      }
      
      logger.debug('TransferFundsModal: User data from localStorage', { user });
      logger.debug('TransferFundsModal: Available user fields', { fields: Object.keys(user) });
      
      // For business accounts and business members, use business_id; for individual, use user.id
      const userType = user.usertype?.toLowerCase();
      const isBusinessAccount = userType === 'business_contact' || userType === 'business';
      const isBusinessMember = userType === 'business_member';
      
      // For business members, extract business_id from team_members[0].teams.business_id
      if (isBusinessMember) {
        const businessId = 
          user?.team_members?.[0]?.teams?.business_id ||
          user?.team_members?.[0]?.teams?.businessId ||
          null;
        
        if (businessId) {
          logger.debug('TransferFundsModal: Using business_id as senderId (business member)', { businessId });
          return businessId;
        }
        logger.warn('TransferFundsModal: Business member but no business_id found in team_members', { userType });
      }
      
      if (isBusinessAccount) {
        // Business account: resolve business_id for x-user-id header
        const businessId = 
          user?.businesses?.[0]?.id || 
          user?.business?.id || 
          user?.business_id || 
          user?.businessId;
        
        if (businessId) {
          logger.debug('TransferFundsModal: Using business_id as senderId (business account)', { businessId });
          return businessId;
        }
        logger.warn('TransferFundsModal: Business account but no business_id found', { userType });
      }
      
      // Individual account: use user.id
      const userId = user.id;
      if (userId) {
        logger.debug('TransferFundsModal: Using user.id as senderId (individual account)', { userId });
        return userId;
      }
      
      // Fallback to other possible fields
      const fallbackId = user.userId || user.user_id || user.user?.id;
      if (fallbackId) {
        logger.warn('TransferFundsModal: Using fallback ID field', { fallbackId });
        return fallbackId;
      }
      
      logger.error('TransferFundsModal: No user ID found in user data');
      return null;
    } catch (error) {
      logger.error('Failed to resolve sender ID from user data', { error });
      return null;
    }
  }, []);

  return { senderId };
};

