/**
 * Custom Hook for Transfer Recipient Search
 * 
 * Manages recipient search functionality with debouncing.
 */

import { useState, useCallback, useRef, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { disbursementService } from '@/features/disbursements/services';
import { cleanNumberForBackend } from '@/shared/utils/format-utils.js';
import { logger } from '@/shared/utils/logger.js';

export const useTransferRecipientSearch = () => {
  const { t } = useTranslation();
  const { error: showError } = useToast();
  const [searchResults, setSearchResults] = useState([]);
  const [isSearching, setIsSearching] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const debounceTimeoutRef = useRef(null);
  const searchContainerRef = useRef(null);

  const searchRecipients = useCallback(async (query, countryCode) => {
    const trimmed = query.trim();

    // Require minimum 3 characters to reduce unnecessary API calls
    if (!trimmed || trimmed.length < 3) {
      setSearchResults([]);
      setIsSearching(false);
      return;
    }

    setIsSearching(true);
    try {
      const nationalDigits = cleanNumberForBackend(trimmed);
      const countryDigits = cleanNumberForBackend(countryCode || '+233');
      const phoneNumber = `${countryDigits}${nationalDigits}`;

      const results = await disbursementService.searchWalletRecipients(phoneNumber);
      setSearchResults(Array.isArray(results) ? results : []);
    } catch (err) {
      logger.error('Failed to search recipients', { error: err });
      setSearchResults([]);
      showError(err.message || t('transferSearchFailed', { ns: 'wallet' }));
    } finally {
      setIsSearching(false);
    }
  }, [showError, t]);

  const debouncedSearch = useCallback((query, countryCode) => {
    if (debounceTimeoutRef.current) {
      clearTimeout(debounceTimeoutRef.current);
    }

    debounceTimeoutRef.current = setTimeout(() => {
      searchRecipients(query, countryCode);
    }, 300); // Reduced to 300ms for better "live" feel while typing
  }, [searchRecipients]);

  // Close results when clicking outside
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (searchContainerRef.current && !searchContainerRef.current.contains(event.target)) {
        setShowResults(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const clearSearch = useCallback(() => {
    setSearchResults([]);
    setShowResults(false);
  }, []);

  return {
    searchResults,
    isSearching,
    showResults,
    setShowResults,
    searchContainerRef,
    debouncedSearch,
    clearSearch,
  };
};

