/**
 * Custom Hook for Transfer Fee Calculation
 * 
 * Manages fee calculation for wallet transfers.
 */

import { useState, useEffect } from 'react';
import { disbursementService } from '@/features/disbursements/services';
import { logger } from '@/shared/utils/logger.js';

export const useTransferFeeCalculation = (amount, serviceId) => {
  const [feeData, setFeeData] = useState(null);
  const [isCheckingFee, setIsCheckingFee] = useState(false);

  useEffect(() => {
    const checkFee = async () => {
      if (!amount || Number(amount) <= 0 || !serviceId) {
        setFeeData(null);
        return;
      }

      setIsCheckingFee(true);
      try {
        const response = await disbursementService.checkFullPayable({
          amount: amount.toString(),
          channel: 'WALLET',
          serviceId: serviceId,
        });

        logger.debug('Fee checker API response', { response });

        if (response?.code === '00' && response?.data) {
          logger.debug('Setting fee data', { data: response.data });
          // Normalize fee values to numbers
          const feeValue = response.data.feeApplied || response.data.fee || '0';
          const totalValue = response.data.total || response.data.totalPayable || amount;
          const baseAmountValue = response.data.baseAmount || amount;
          
          const feeInfo = {
            feeApplied: typeof feeValue === 'string' ? parseFloat(feeValue) : feeValue,
            total: typeof totalValue === 'string' ? parseFloat(totalValue) : totalValue,
            baseAmount: typeof baseAmountValue === 'string' ? parseFloat(baseAmountValue) : baseAmountValue,
            feeType: response.data.feeType,
            feeSource: response.data.feeSource,
            channel: response.data.channel || 'WALLET'
          };
          logger.debug('Processed fee info', { feeInfo });
          setFeeData(feeInfo);
        } else {
          logger.warn('Invalid fee response', { response });
          setFeeData(null);
        }
      } catch (error) {
        logger.error('Failed to check fee', { error });
        setFeeData(null);
      } finally {
        setIsCheckingFee(false);
      }
    };

    // Debounce fee check
    const timeoutId = setTimeout(() => {
      checkFee();
    }, 500);

    return () => clearTimeout(timeoutId);
  }, [amount, serviceId]);

  return {
    feeData,
    isCheckingFee,
  };
};

